import pandas as pd, ast, re
from collections import Counter
df = pd.read_csv('/work/ferc_search_20260614_053818.csv')

# Count AUTHOR entities per filing (unique authors per filing)
author_counter = Counter()
for _, row in df.iterrows():
    affs = row['affiliations']
    try:
        affs = ast.literal_eval(affs)
    except:
        affs = []
    authors = set()
    for a in affs:
        if a.startswith('AUTHOR:'):
            name = a.replace('AUTHOR:','').strip()
            authors.add(name)
    for name in authors:
        author_counter[name]+=1

for name,c in author_counter.most_common(15):
    print(c, name)

